if (!raw_token) {
  return [{ json: { 
    mode: "instructions",
    chat_id: ctx.chat_id,
    user_id: ctx.user_id
  }}];
}

// Check if it's in api_key:access_token format
if (raw_token.includes(":")) {
  const parts = raw_token.split(":");
  const api_key = parts[0];
  const access_token = parts[1];
  return [{ json: {
    mode: "store_token",
    chat_id: ctx.chat_id,
    user_id: ctx.user_id,
    access_token: access_token,
    api_key: api_key
  }}];
}

// Single token - it's a request_token that needs exchange
return [{ json: {
  mode: "exchange",
  chat_id: ctx.chat_id,
  user_id: ctx.user_id,
  request_token: raw_token
}}];

