const api_secret = db.api_secret;
const request_token = prev.request_token;

if (!api_secret) {
  // No API secret in DB - can't exchange. Tell user.
  return [{ json: {
    error: true,
    chat_id: prev.chat_id,
    user_id: prev.user_id,
    message: "⚠️ *Kite API Secret Not Configured*\n\nThe Kite API secret is not set up yet. Please contact admin to configure `kite_api_secret_encrypted` in the users table.\n\nAlternatively, you can provide your access token directly:\n`login api_key:access_token`"
  }}];
}

// Compute SHA256 checksum: api_key + request_token + api_secret
const checksum = crypto.createHash('sha256')
  .update(api_key + request_token + api_secret)
  .digest('hex');

return [{ json: {
  error: false,
  chat_id: prev.chat_id,
  user_id: prev.user_id,
  api_key: api_key,
  request_token: request_token,
  checksum: checksum
}}];

